                DisplayName        = $_.DisplayName
                LastSignInDateTime = if ([string]::IsNullOrEmpty($_.LastSignInDateTime)) { "Never" } 
                                    else { [DateTime]::Parse($_.LastSignInDateTime).ToString("yyyy-MM-ddTHH:mm:ssZ") }
                AccountEnabled     = $_.AccountEnabled
